const express = require('express');
const http = require('http');
const { Server } = require('socket.io');
const crypto = require('crypto');

const app = express();
const server = http.createServer(app);
const io = new Server(server, {
  cors: {
    origin: '*',
    methods: ['GET', 'POST']
  }
});

app.use(express.json());

const PORT = process.env.PORT || 3000;
const SESSION_TTL_MS = 1000 * 60 * 60 * 24;
const USERNAME_REGEX = /^[a-zA-Z0-9_]{3,20}$/;

const users = new Map();
const sessions = new Map();
const players = new Map();
const leaderboard = new Map();

function now() {
  return Date.now();
}

function hashPassword(password, salt) {
  return crypto.pbkdf2Sync(password, salt, 100000, 64, 'sha512').toString('hex');
}

function createSession(username) {
  const token = crypto.randomBytes(32).toString('hex');
  sessions.set(token, {
    username,
    createdAt: now(),
    expiresAt: now() + SESSION_TTL_MS
  });
  return token;
}

function getSession(token) {
  const session = sessions.get(token);
  if (!session) return null;
  if (session.expiresAt < now()) {
    sessions.delete(token);
    return null;
  }
  session.expiresAt = now() + SESSION_TTL_MS;
  return session;
}

function sanitizeUsername(username) {
  if (typeof username !== 'string') return null;
  const trimmed = username.trim();
  if (!USERNAME_REGEX.test(trimmed)) return null;
  return trimmed;
}

function sanitizeScore(score) {
  const n = Number(score);
  if (!Number.isFinite(n) || n < 0) return null;
  return Math.floor(n);
}

app.post('/register', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : null;

  if (!username || !password || password.length < 6) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  if (users.has(username)) {
    return res.status(409).json({ error: 'User already exists' });
  }

  const salt = crypto.randomBytes(16).toString('hex');
  const passwordHash = hashPassword(password, salt);

  users.set(username, {
    username,
    salt,
    passwordHash,
    createdAt: now()
  });

  leaderboard.set(username, 0);

  const token = createSession(username);
  return res.json({ token, username });
});

app.post('/login', (req, res) => {
  const username = sanitizeUsername(req.body.username);
  const password = typeof req.body.password === 'string' ? req.body.password : null;

  if (!username || !password) {
    return res.status(400).json({ error: 'Invalid username or password' });
  }

  const user = users.get(username);
  if (!user) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const passwordHash = hashPassword(password, user.salt);
  if (passwordHash !== user.passwordHash) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  const token = createSession(username);
  return res.json({ token, username });
});

app.post('/logout', (req, res) => {
  const auth = req.headers.authorization || '';
  const token = auth.startsWith('Bearer ') ? auth.slice(7) : null;

  if (token) {
    sessions.delete(token);
  }

  res.json({ ok: true });
});

app.get('/leaderboard', (req, res) => {
  const top = [...leaderboard.entries()]
    .map(([username, score]) => ({ username, score }))
    .sort((a, b) => b.score - a.score)
    .slice(0, 100);

  res.json({ leaderboard: top });
});

io.use((socket, next) => {
  const token = socket.handshake.auth?.token || socket.handshake.headers['x-session-token'];
  if (!token || typeof token !== 'string') {
    return next(new Error('Unauthorized'));
  }

  const session = getSession(token);
  if (!session) {
    return next(new Error('Invalid session'));
  }

  socket.sessionToken = token;
  socket.username = session.username;
  next();
});

io.on('connection', (socket) => {
  const username = socket.username;

  players.set(socket.id, {
    socketId: socket.id,
    username,
    connectedAt: now(),
    x: 0,
    y: 0,
    score: leaderboard.get(username) || 0
  });

  socket.emit('authenticated', {
    username,
    score: leaderboard.get(username) || 0
  });

  io.emit('player_joined', {
    socketId: socket.id,
    username
  });

  socket.on('move', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    const x = Number(payload.x);
    const y = Number(payload.y);

    if (!Number.isFinite(x) || !Number.isFinite(y)) {
      return socket.emit('error_message', { error: 'Invalid move payload' });
    }

    player.x = x;
    player.y = y;

    io.emit('player_moved', {
      socketId: socket.id,
      username: player.username,
      x: player.x,
      y: player.y
    });
  });

  socket.on('score_update', (payload = {}) => {
    const player = players.get(socket.id);
    if (!player) return;

    const score = sanitizeScore(payload.score);
    if (score === null) {
      return socket.emit('error_message', { error: 'Invalid score' });
    }

    player.score = score;
    leaderboard.set(player.username, score);

    io.emit('score_updated', {
      username: player.username,
      score
    });
  });

  socket.on('get_state', () => {
    const state = [...players.values()].map((p) => ({
      socketId: p.socketId,
      username: p.username,
      x: p.x,
      y: p.y,
      score: p.score
    }));

    socket.emit('state', { players: state });
  });

  socket.on('disconnect', () => {
    const player = players.get(socket.id);
    players.delete(socket.id);

    if (player) {
      io.emit('player_left', {
        socketId: socket.id,
        username: player.username
      });
    }
  });
});

setInterval(() => {
  const t = now();
  for (const [token, session] of sessions.entries()) {
    if (session.expiresAt < t) {
      sessions.delete(token);
    }
  }
}, 60 * 1000);

server.listen(PORT, () => {
  console.log(`Server listening on port ${PORT}`);
});